Write-Host "=== Remplacement de toutes les pages par donnees demo ===" -ForegroundColor Cyan
function Write-B64 { param($p,$b)
  $full = Join-Path (Get-Location).Path $p
  $dir = Split-Path $full -Parent
  if ($dir -and -not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  $bytes = [Convert]::FromBase64String($b)
  $text = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($full, $text, (New-Object System.Text.UTF8Encoding $false))
  Write-Host "  -> $p" -ForegroundColor Gray
}

Write-B64 "frontend\src\ui\pages\AuditPage.tsx" ""
Write-B64 "frontend\src\ui\pages\BudgetPage.tsx" ""
Write-B64 "frontend\src\ui\pages\ProcurementPage.tsx" ""
Write-B64 "frontend\src\ui\pages\RevenuePage.tsx" ""
Write-B64 "frontend\src\ui\pages\ExportsPage.tsx" ""
Write-B64 "frontend\src\ui\pages\AiPage.tsx" ""
Write-B64 "frontend\src\ui\pages\AdminPage.tsx" ""

git add -A
$c = git commit -m "feat: toutes les pages en mode demo — donnees statiques SN, zero appel API" 2>&1
Write-Host "  $c" -ForegroundColor Gray
$p = git push origin main 2>&1
Write-Host "  $p" -ForegroundColor Gray
Write-Host "TERMINE — toutes les pages fonctionnent sans backend." -ForegroundColor Green
Write-Host "https://budgetnew.vercel.app" -ForegroundColor Cyan